'use client';

import { useBookingStore, TRANSPORT_OPTIONS } from '@/store/booking-store';

export default function StepTransport() {
  const { 
    selectedTransport, 
    setSelectedTransport, 
    adults, 
    children,
    getTripDuration
  } = useBookingStore();
  
  const totalPeople = adults + children;
  const tripDuration = getTripDuration();

  // Vehicle icons as simple SVG components
  const VehicleIcon = ({ type }: { type: string }) => {
    switch (type) {
      case 'sedan':
        return (
          <svg className="w-full h-full" viewBox="0 0 64 32" fill="currentColor">
            <path d="M56 20h-2v-4c0-1.1-.4-2.1-1.1-2.9l-5.1-5.7c-.9-1-2.2-1.4-3.5-1.4H19.7c-1.3 0-2.6.5-3.5 1.4l-5.1 5.7c-.7.8-1.1 1.8-1.1 2.9v4H8c-1.1 0-2 .9-2 2s.9 2 2 2h2v2c0 1.1.9 2 2 2h4c1.1 0 2-.9 2-2v-2h28v2c0 1.1.9 2 2 2h4c1.1 0 2-.9 2-2v-2h2c1.1 0 2-.9 2-2s-.9-2-2-2zM16 20c-1.1 0-2-.9-2-2s.9-2 2-2 2 .9 2 2-.9 2-2 2zm32 0c-1.1 0-2-.9-2-2s.9-2 2-2 2 .9 2 2-.9 2-2 2zm2-6H14l4-4.5c.2-.2.5-.5.9-.5h26.2c.4 0 .7.2.9.5l4 4.5z"/>
          </svg>
        );
      case 'suv':
        return (
          <svg className="w-full h-full" viewBox="0 0 64 32" fill="currentColor">
            <path d="M58 18h-2v-6c0-1.1-.4-2.1-1.1-2.9l-4.1-4.7c-.9-1-2.2-1.4-3.5-1.4H16.7c-1.3 0-2.6.5-3.5 1.4l-4.1 4.7c-.7.8-1.1 1.8-1.1 2.9v6H6c-1.1 0-2 .9-2 2s.9 2 2 2h2v4c0 1.1.9 2 2 2h4c1.1 0 2-.9 2-2v-2h32v2c0 1.1.9 2 2 2h4c1.1 0 2-.9 2-2v-4h2c1.1 0 2-.9 2-2s-.9-2-2-2zM14 20c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3zm36 0c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3zM12 12l3-3.5c.2-.2.5-.5.9-.5h32.2c.4 0 .7.2.9.5l3 3.5H12z"/>
          </svg>
        );
      case 'minivan':
        return (
          <svg className="w-full h-full" viewBox="0 0 64 32" fill="currentColor">
            <path d="M58 16h-3V8c0-2.2-1.8-4-4-4H13c-2.2 0-4 1.8-4 4v8H6c-1.1 0-2 .9-2 2s.9 2 2 2h2v4c0 2.2 1.8 4 4 4h2c1.1 0 2-.9 2-2v-2h32v2c0 1.1.9 2 2 2h2c2.2 0 4-1.8 4-4v-4h2c1.1 0 2-.9 2-2s-.9-2-2-2zM14 22c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3zm3-10H13V8h4v4zm8 0h-4V8h4v4zm8 0h-4V8h4v4zm8 0h-4V8h4v4zm9 10c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3z"/>
          </svg>
        );
      case 'sprinter':
        return (
          <svg className="w-full h-full" viewBox="0 0 64 32" fill="currentColor">
            <path d="M60 14h-4V6c0-1.1-.9-2-2-2H10c-2.2 0-4 1.8-4 4v12H4c-1.1 0-2 .9-2 2s.9 2 2 2h2v2c0 2.2 1.8 4 4 4h2c1.1 0 2-.9 2-2v-2h36v2c0 1.1.9 2 2 2h2c2.2 0 4-1.8 4-4v-2h2c1.1 0 2-.9 2-2s-.9-2-2-2zM12 24c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3zm40 0c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3zM10 14V8h6v6h-6zm10 0V8h6v6h-6zm10 0V8h6v6h-6zm10 0V8h6v6h-6zm14 0h-6V8h6v6z"/>
          </svg>
        );
      case 'bus':
        return (
          <svg className="w-full h-full" viewBox="0 0 64 32" fill="currentColor">
            <path d="M56 4H8c-2.2 0-4 1.8-4 4v16c0 2.2 1.8 4 4 4h2v2c0 1.1.9 2 2 2h4c1.1 0 2-.9 2-2v-2h28v2c0 1.1.9 2 2 2h4c1.1 0 2-.9 2-2v-2h2c2.2 0 4-1.8 4-4V8c0-2.2-1.8-4-4-4zM12 26c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3zm40 0c-1.7 0-3-1.3-3-3s1.3-3 3-3 3 1.3 3 3-1.3 3-3 3zM8 16V8h8v8H8zm12 0V8h8v8h-8zm12 0V8h8v8h-8zm12 0V8h8v8h-8zm12 0V8h8v8h-8z"/>
          </svg>
        );
      default:
        return null;
    }
  };

  return (
    <div className="animate-fade-in-up">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900">Choose your transport</h2>
        <p className="mt-1 text-gray-500">
          Select a vehicle for {totalPeople} {totalPeople === 1 ? 'traveler' : 'travelers'}
        </p>
      </div>

      <div className="space-y-3">
        {TRANSPORT_OPTIONS.map((transport) => {
          const isSelected = selectedTransport === transport.id;
          const hasEnoughCapacity = transport.capacity >= totalPeople;
          const priceForTrip = transport.pricePerDay * Math.max(1, tripDuration);
          
          return (
            <button
              key={transport.id}
              onClick={() => setSelectedTransport(transport.id)}
              disabled={!hasEnoughCapacity}
              className={`
                w-full text-left p-4 rounded-2xl transition-all duration-200
                ${isSelected 
                  ? 'bg-[#25D366]/5 border-2 border-[#25D366] shadow-lg shadow-[#25D366]/10' 
                  : hasEnoughCapacity
                    ? 'bg-white border-2 border-gray-100 hover:border-gray-200 hover:shadow-md'
                    : 'bg-gray-50 border-2 border-gray-100 opacity-60 cursor-not-allowed'
                }
              `}
            >
              <div className="flex items-start gap-4">
                {/* Vehicle illustration */}
                <div className={`
                  w-20 h-14 flex items-center justify-center rounded-xl flex-shrink-0
                  ${isSelected ? 'bg-[#25D366]/10 text-[#25D366]' : 'bg-gray-100 text-gray-400'}
                `}>
                  <VehicleIcon type={transport.id} />
                </div>
                
                {/* Content */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <h3 className={`font-semibold ${isSelected ? 'text-[#25D366]' : 'text-gray-900'}`}>
                        {transport.title}
                      </h3>
                      <p className="text-sm text-gray-500 mt-0.5">{transport.description}</p>
                    </div>
                    
                    {/* Selection indicator */}
                    <div className={`
                      w-6 h-6 rounded-full flex-shrink-0 flex items-center justify-center
                      transition-all duration-200
                      ${isSelected 
                        ? 'bg-[#25D366] text-white' 
                        : 'border-2 border-gray-300'
                      }
                    `}>
                      {isSelected && (
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                        </svg>
                      )}
                    </div>
                  </div>
                  
                  {/* Meta info */}
                  <div className="flex items-center gap-3 mt-3">
                    <span className={`
                      inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium
                      ${hasEnoughCapacity 
                        ? 'bg-gray-100 text-gray-600' 
                        : 'bg-red-50 text-red-600'
                      }
                    `}>
                      <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z" />
                      </svg>
                      {hasEnoughCapacity 
                        ? `Up to ${transport.capacity}` 
                        : `Only fits ${transport.capacity}`
                      }
                    </span>
                    
                    <span className="text-sm font-semibold text-gray-900">
                      ${transport.pricePerDay}
                      <span className="text-gray-400 font-normal">/day</span>
                    </span>
                    
                    {tripDuration > 0 && (
                      <span className="text-sm text-[#25D366] font-medium">
                        ${priceForTrip} total
                      </span>
                    )}
                  </div>
                </div>
              </div>
            </button>
          );
        })}
      </div>

      {/* Capacity warning */}
      {!TRANSPORT_OPTIONS.some(t => t.capacity >= totalPeople) && (
        <div className="mt-4 px-4 py-3 bg-amber-50 rounded-xl">
          <div className="flex items-start gap-2 text-sm">
            <svg className="w-5 h-5 text-amber-500 flex-shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
            <span className="text-amber-700">
              Your group is larger than our largest vehicle. Please contact us for custom arrangements.
            </span>
          </div>
        </div>
      )}
    </div>
  );
}
