'use client';

import { useBookingStore } from '@/store/booking-store';

interface BottomNavProps {
  onNext?: () => void;
  onBack?: () => void;
}

export default function BottomNav({ onNext, onBack }: BottomNavProps) {
  const { 
    currentStep, 
    setCurrentStep, 
    getStepValidation, 
    markStepComplete,
    getTotalPrice,
    getTripDuration 
  } = useBookingStore();

  const validation = getStepValidation(currentStep);
  const isFirstStep = currentStep === 1;
  const isLastPartOneStep = currentStep === 4;
  const tripDuration = getTripDuration();
  const totalPrice = getTotalPrice();

  const handleBack = () => {
    if (onBack) {
      onBack();
    } else if (!isFirstStep) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleNext = () => {
    if (!validation.isValid) return;
    
    markStepComplete(currentStep);
    
    if (onNext) {
      onNext();
    } else if (!isLastPartOneStep) {
      setCurrentStep(currentStep + 1);
    }
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 shadow-[0_-4px_20px_rgba(0,0,0,0.05)]">
      {/* Price preview (shown when we have some data) */}
      {(tripDuration > 0 || totalPrice > 0) && (
        <div className="px-4 py-2 bg-gray-50 border-b border-gray-100 flex justify-between text-sm">
          {tripDuration > 0 && (
            <span className="text-gray-500">
              {tripDuration} {tripDuration === 1 ? 'day' : 'days'}
            </span>
          )}
          {totalPrice > 0 && (
            <span className="font-semibold text-gray-800">
              ${totalPrice.toLocaleString()}
            </span>
          )}
        </div>
      )}
      
      {/* Navigation buttons */}
      <div className="px-4 py-3 pb-[max(12px,env(safe-area-inset-bottom))] flex gap-3">
        {/* Back button */}
        <button
          onClick={handleBack}
          disabled={isFirstStep}
          className={`
            flex-1 py-3.5 px-6 rounded-xl font-semibold text-base
            transition-all duration-200 active:scale-[0.98]
            ${isFirstStep 
              ? 'text-gray-300 cursor-not-allowed' 
              : 'text-gray-600 hover:bg-gray-100 active:bg-gray-200'
            }
          `}
        >
          Back
        </button>
        
        {/* Next button */}
        <button
          onClick={handleNext}
          disabled={!validation.isValid}
          className={`
            flex-1 py-3.5 px-6 rounded-xl font-semibold text-base
            transition-all duration-200 active:scale-[0.98]
            ${validation.isValid
              ? 'bg-[#25D366] text-white hover:bg-[#1da851] active:bg-[#189945] shadow-lg shadow-[#25D366]/25'
              : 'bg-gray-200 text-gray-400 cursor-not-allowed'
            }
          `}
        >
          {isLastPartOneStep ? 'Continue to Tours' : 'Next'}
        </button>
      </div>
      
      {/* Validation error message */}
      {!validation.isValid && validation.error && (
        <div className="absolute -top-8 left-4 right-4 text-center">
          <span className="inline-block px-3 py-1 bg-red-50 text-red-600 text-xs font-medium rounded-full">
            {validation.error}
          </span>
        </div>
      )}
    </div>
  );
}
