'use client';

import { useState, useMemo } from 'react';
import { useBookingStore } from '@/store/booking-store';
import { format, addDays, isBefore, isAfter, isSameDay, startOfDay } from 'date-fns';
import { DayPicker, DateRange } from 'react-day-picker';
import 'react-day-picker/style.css';

export default function StepDates() {
  const { startDate, endDate, setStartDate, setEndDate } = useBookingStore();
  
  const [range, setRange] = useState<DateRange | undefined>(() => {
    if (startDate && endDate) {
      return { from: new Date(startDate), to: new Date(endDate) };
    }
    if (startDate) {
      return { from: new Date(startDate), to: undefined };
    }
    return undefined;
  });

  const today = useMemo(() => startOfDay(new Date()), []);
  const maxDate = useMemo(() => addDays(today, 365), [today]);

  const handleRangeSelect = (newRange: DateRange | undefined) => {
    setRange(newRange);
    
    if (newRange?.from) {
      setStartDate(newRange.from.toISOString());
    } else {
      setStartDate(null);
    }
    
    if (newRange?.to) {
      setEndDate(newRange.to.toISOString());
    } else {
      setEndDate(null);
    }
  };

  const tripDuration = useMemo(() => {
    if (!range?.from || !range?.to) return 0;
    const diffTime = Math.abs(range.to.getTime() - range.from.getTime());
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  }, [range]);

  return (
    <div className="animate-fade-in-up">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900">When are you going?</h2>
        <p className="mt-1 text-gray-500">Select your travel dates</p>
      </div>

      {/* Date summary cards */}
      <div className="grid grid-cols-2 gap-3 mb-5">
        <div className={`
          p-4 rounded-xl transition-all duration-200
          ${range?.from 
            ? 'bg-[#25D366]/10 border-2 border-[#25D366]' 
            : 'bg-white border-2 border-gray-200'
          }
        `}>
          <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">Start</span>
          <p className={`mt-1 font-semibold ${range?.from ? 'text-gray-900' : 'text-gray-400'}`}>
            {range?.from ? format(range.from, 'MMM d, yyyy') : 'Select date'}
          </p>
        </div>
        
        <div className={`
          p-4 rounded-xl transition-all duration-200
          ${range?.to 
            ? 'bg-[#25D366]/10 border-2 border-[#25D366]' 
            : 'bg-white border-2 border-gray-200'
          }
        `}>
          <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">End</span>
          <p className={`mt-1 font-semibold ${range?.to ? 'text-gray-900' : 'text-gray-400'}`}>
            {range?.to ? format(range.to, 'MMM d, yyyy') : 'Select date'}
          </p>
        </div>
      </div>

      {/* Calendar */}
      <div className="bg-white rounded-2xl p-4 shadow-sm overflow-hidden">
        <style jsx global>{`
          .rdp-root {
            --rdp-accent-color: #25D366;
            --rdp-accent-background-color: #25D366;
            --rdp-range_start-color: white;
            --rdp-range_end-color: white;
            --rdp-range_middle-color: #1a7f37;
            --rdp-range_middle-background-color: #dcf8c6;
            margin: 0 auto;
            font-family: inherit;
          }
          .rdp-month_caption {
            font-weight: 600;
            font-size: 1rem;
            padding: 0.5rem 0;
          }
          .rdp-weekday {
            font-weight: 500;
            color: #9ca3af;
            font-size: 0.75rem;
          }
          .rdp-day {
            border-radius: 9999px;
            font-weight: 500;
          }
          .rdp-day_button {
            width: 40px;
            height: 40px;
            border-radius: 9999px;
          }
          .rdp-selected .rdp-day_button {
            background-color: #25D366;
            color: white;
          }
          .rdp-range_middle .rdp-day_button {
            background-color: #dcf8c6;
            color: #1a7f37;
            border-radius: 0;
          }
          .rdp-range_start .rdp-day_button {
            border-top-right-radius: 0;
            border-bottom-right-radius: 0;
          }
          .rdp-range_end .rdp-day_button {
            border-top-left-radius: 0;
            border-bottom-left-radius: 0;
          }
          .rdp-today:not(.rdp-selected) .rdp-day_button {
            border: 2px solid #25D366;
            font-weight: 700;
          }
          .rdp-disabled .rdp-day_button {
            color: #d1d5db;
          }
          .rdp-chevron {
            fill: #25D366;
          }
        `}</style>
        
        <DayPicker
          mode="range"
          selected={range}
          onSelect={handleRangeSelect}
          disabled={{ before: today }}
          startMonth={today}
          endMonth={maxDate}
          showOutsideDays={false}
          fixedWeeks
        />
      </div>

      {/* Trip duration display */}
      {tripDuration > 0 && (
        <div className="mt-4 px-4 py-3 bg-[#dcf8c6]/50 rounded-xl">
          <div className="flex items-center gap-2 text-sm">
            <svg className="w-5 h-5 text-[#25D366]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
            <span className="text-gray-700">
              <span className="font-semibold">{tripDuration}</span> {tripDuration === 1 ? 'day' : 'days'} trip
              {tripDuration > 1 && (
                <span className="text-gray-500"> • {tripDuration - 1} {tripDuration - 1 === 1 ? 'night' : 'nights'}</span>
              )}
            </span>
          </div>
        </div>
      )}

      {/* Quick select options */}
      <div className="mt-4">
        <p className="text-xs font-medium text-gray-500 uppercase tracking-wide mb-2">Quick select</p>
        <div className="flex gap-2 overflow-x-auto pb-1">
          {[
            { label: 'Weekend', days: 2 },
            { label: '1 Week', days: 7 },
            { label: '2 Weeks', days: 14 },
          ].map((option) => (
            <button
              key={option.label}
              onClick={() => {
                const from = today;
                const to = addDays(today, option.days);
                handleRangeSelect({ from, to });
              }}
              className="px-4 py-2 bg-white border border-gray-200 rounded-full text-sm font-medium text-gray-700 hover:border-[#25D366] hover:text-[#25D366] transition-colors whitespace-nowrap"
            >
              {option.label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
