'use client';

import { useBookingStore } from '@/store/booking-store';

const STEPS = [
  { number: 1, label: 'Party' },
  { number: 2, label: 'Dates' },
  { number: 3, label: 'Transport' },
  { number: 4, label: 'Guide' },
];

export default function ProgressBar() {
  const { currentStep, completedSteps, getStepValidation } = useBookingStore();

  return (
    <div className="w-full px-4 py-3">
      <div className="flex items-center justify-between relative">
        {/* Progress line background */}
        <div className="absolute top-4 left-6 right-6 h-0.5 bg-gray-200" />
        
        {/* Active progress line */}
        <div 
          className="absolute top-4 left-6 h-0.5 bg-[#25D366] transition-all duration-500 ease-out"
          style={{ 
            width: `calc(${((currentStep - 1) / (STEPS.length - 1)) * 100}% - ${currentStep === 1 ? 0 : 0}px)`,
            maxWidth: 'calc(100% - 48px)'
          }}
        />
        
        {/* Step indicators */}
        {STEPS.map((step) => {
          const isCompleted = completedSteps.includes(step.number) || step.number < currentStep;
          const isCurrent = step.number === currentStep;
          const validation = getStepValidation(step.number);
          const isValid = validation.isValid;
          
          return (
            <div 
              key={step.number} 
              className="flex flex-col items-center z-10"
            >
              <div
                className={`
                  w-8 h-8 rounded-full flex items-center justify-center text-sm font-semibold
                  transition-all duration-300 ease-out
                  ${isCurrent 
                    ? 'bg-[#25D366] text-white scale-110 shadow-lg shadow-[#25D366]/30' 
                    : isCompleted 
                      ? 'bg-[#25D366] text-white' 
                      : 'bg-gray-100 text-gray-400 border-2 border-gray-200'
                  }
                `}
              >
                {isCompleted && !isCurrent ? (
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                  </svg>
                ) : (
                  step.number
                )}
              </div>
              <span 
                className={`
                  mt-1.5 text-xs font-medium transition-colors duration-300
                  ${isCurrent ? 'text-[#25D366]' : isCompleted ? 'text-gray-600' : 'text-gray-400'}
                `}
              >
                {step.label}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
