'use client';

import { useBookingStore } from '@/store/booking-store';

interface CounterRowProps {
  label: string;
  sublabel: string;
  value: number;
  onIncrement: () => void;
  onDecrement: () => void;
  minValue?: number;
  maxValue?: number;
}

function CounterRow({ 
  label, 
  sublabel, 
  value, 
  onIncrement, 
  onDecrement,
  minValue = 0,
  maxValue = 20 
}: CounterRowProps) {
  const canDecrement = value > minValue;
  const canIncrement = value < maxValue;

  return (
    <div className="flex items-center justify-between py-5 border-b border-gray-100 last:border-b-0">
      <div className="flex flex-col">
        <span className="text-lg font-semibold text-gray-800">{label}</span>
        <span className="text-sm text-gray-500">{sublabel}</span>
      </div>
      
      <div className="flex items-center gap-4">
        {/* Decrement button */}
        <button
          onClick={onDecrement}
          disabled={!canDecrement}
          aria-label={`Decrease ${label}`}
          className={`
            w-12 h-12 rounded-full flex items-center justify-center
            text-2xl font-light transition-all duration-200 active:scale-95
            ${canDecrement 
              ? 'bg-gray-100 text-gray-700 hover:bg-gray-200 active:bg-gray-300' 
              : 'bg-gray-50 text-gray-300 cursor-not-allowed'
            }
          `}
        >
          −
        </button>
        
        {/* Value display */}
        <span className="w-8 text-center text-xl font-semibold text-gray-800 tabular-nums">
          {value}
        </span>
        
        {/* Increment button */}
        <button
          onClick={onIncrement}
          disabled={!canIncrement}
          aria-label={`Increase ${label}`}
          className={`
            w-12 h-12 rounded-full flex items-center justify-center
            text-2xl font-light transition-all duration-200 active:scale-95
            ${canIncrement 
              ? 'bg-[#25D366] text-white hover:bg-[#1da851] active:bg-[#189945] shadow-md shadow-[#25D366]/20' 
              : 'bg-gray-50 text-gray-300 cursor-not-allowed'
            }
          `}
        >
          +
        </button>
      </div>
    </div>
  );
}

export default function StepPartySize() {
  const { adults, children, setAdults, setChildren } = useBookingStore();
  const totalPeople = adults + children;

  return (
    <div className="animate-fade-in-up">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900">Who's traveling?</h2>
        <p className="mt-1 text-gray-500">Tell us about your travel party</p>
      </div>
      
      <div className="bg-white rounded-2xl p-5 shadow-sm">
        <CounterRow
          label="Adults"
          sublabel="Ages 13 or above"
          value={adults}
          onIncrement={() => setAdults(adults + 1)}
          onDecrement={() => setAdults(adults - 1)}
          minValue={1}
          maxValue={20}
        />
        
        <CounterRow
          label="Children"
          sublabel="Ages 2–12"
          value={children}
          onIncrement={() => setChildren(children + 1)}
          onDecrement={() => setChildren(children - 1)}
          minValue={0}
          maxValue={20}
        />
      </div>
      
      {/* Summary card */}
      <div className="mt-4 px-4 py-3 bg-[#dcf8c6]/50 rounded-xl">
        <div className="flex items-center gap-2 text-sm">
          <svg className="w-5 h-5 text-[#25D366]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
          </svg>
          <span className="text-gray-700">
            <span className="font-semibold">{totalPeople}</span> {totalPeople === 1 ? 'traveler' : 'travelers'} total
          </span>
        </div>
      </div>

      {totalPeople > 12 && (
        <div className="mt-3 px-4 py-3 bg-amber-50 rounded-xl">
          <div className="flex items-start gap-2 text-sm">
            <svg className="w-5 h-5 text-amber-500 flex-shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <span className="text-amber-700">
              Large groups may need multiple vehicles. We'll show suitable options in the transport step.
            </span>
          </div>
        </div>
      )}
    </div>
  );
}
