'use client';

import { useEffect, useState } from 'react';
import { useBookingStore } from '@/store/booking-store';
import ProgressBar from './ProgressBar';
import BottomNav from './BottomNav';
import StepPartySize from './steps/StepPartySize';
import StepDates from './steps/StepDates';
import StepTransport from './steps/StepTransport';
import StepGuides from './steps/StepGuides';

export default function BookingWizard() {
  const { currentStep } = useBookingStore();
  const [mounted, setMounted] = useState(false);

  // Handle hydration mismatch with localStorage
  useEffect(() => {
    setMounted(true);
  }, []);

  // Render loading state until client-side hydration completes
  if (!mounted) {
    return (
      <div className="min-h-screen bg-[#fafafa] flex items-center justify-center">
        <div className="flex flex-col items-center gap-3">
          <div className="w-10 h-10 border-3 border-[#25D366] border-t-transparent rounded-full animate-spin" />
          <p className="text-gray-500 text-sm">Loading your booking...</p>
        </div>
      </div>
    );
  }

  const renderStep = () => {
    switch (currentStep) {
      case 1:
        return <StepPartySize />;
      case 2:
        return <StepDates />;
      case 3:
        return <StepTransport />;
      case 4:
        return <StepGuides />;
      default:
        return <StepPartySize />;
    }
  };

  return (
    <div className="min-h-screen bg-[#fafafa] flex flex-col">
      {/* Sticky header */}
      <header className="sticky top-0 z-50 bg-white/95 backdrop-blur-md border-b border-gray-100 shadow-sm">
        <div className="max-w-lg mx-auto">
          {/* Logo/Title area */}
          <div className="px-4 pt-3 pb-1 flex items-center justify-between">
            <div>
              <h1 className="text-lg font-bold text-gray-900">Book Your Trip</h1>
              <p className="text-xs text-gray-500">Step {currentStep} of 4</p>
            </div>
            <ResetButton />
          </div>
          
          {/* Progress bar */}
          <ProgressBar />
        </div>
      </header>

      {/* Main content area */}
      <main className="flex-1 max-w-lg mx-auto w-full px-4 py-6 pb-40">
        {renderStep()}
      </main>

      {/* Fixed bottom navigation */}
      <div className="max-w-lg mx-auto w-full">
        <BottomNav />
      </div>
    </div>
  );
}

function ResetButton() {
  const { resetBooking } = useBookingStore();
  const [showConfirm, setShowConfirm] = useState(false);

  const handleReset = () => {
    resetBooking();
    setShowConfirm(false);
  };

  if (showConfirm) {
    return (
      <div className="flex items-center gap-2">
        <button
          onClick={() => setShowConfirm(false)}
          className="px-3 py-1.5 text-xs font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
        >
          Cancel
        </button>
        <button
          onClick={handleReset}
          className="px-3 py-1.5 text-xs font-medium text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
        >
          Reset
        </button>
      </div>
    );
  }

  return (
    <button
      onClick={() => setShowConfirm(true)}
      className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
      aria-label="Reset booking"
    >
      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
      </svg>
    </button>
  );
}
